import React, { useEffect, useState } from "react";
import CartItem from "../components/cart/components/CartItem";
import OrderSummary from "../components/cart/components/OrderSummary";
import CartItemSkeleton from "../components/cart/components/CartItemSkeleton";
import { Footer, Navbar } from "../components";
import { useCart } from "../components/contexts/CartContext";
import { useNavigate } from "react-router-dom";

const CartPage = () => {
  const navigate = useNavigate();
  const { fetchCart, cart, loading } = useCart();
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchCart().catch(() => setError("Failed to load cart"));
  }, [fetchCart]);

  const handleCheckout = () => {
    if (!cart?.items?.length) return;
    navigate("/checkout");
  };

  return (
    <>
      <Navbar />

      <div className="py-20 max-container padding-container">
        <h2 className="text-3xl font-bold mb-8">Shopping Cart</h2>

        <div className="grid lg:grid-cols-2 gap-8">
          <div className="space-y-2 bg-white shadow p-4">
            {loading ? (
              Array.from({ length: 3 }).map((_, i) => (
                <CartItemSkeleton key={i} />
              ))
            ) : error ? (
              <p className="text-red-500">{error}</p>
            ) : cart?.items?.length === 0 ? (
              <p>Cart is empty</p>
            ) : (
              cart.items.map((item) => (
                <CartItem key={item.id} cartItem={item} />
              ))
            )}

            {cart?.items?.length > 0 && (
              <button
                onClick={handleCheckout}
                className="mt-6 w-full bg-[#800020] text-white py-2 rounded"
              >
                Checkout
              </button>
            )}
          </div>

          <OrderSummary cart={cart} />
        </div>
      </div>

      <Footer />
    </>
  );
};

export default CartPage;
